class Solution:
    def smallestNumber(self, pattern: str) -> str:
        nums = list('123456789')
        res = []
        stack = []

        for p in pattern:
            if p == 'I':
                res.append(nums.pop(0))
                while stack:
                    res.append(stack.pop())
            else:
                stack.append(nums.pop(0))

        res.append(nums.pop(0))
        while stack:
            res.append(stack.pop())

        return ''.join(res)
